// // This comment suggests that the counter decrements on each rising edge of the clock and resets to 0xFF when the reset signal is high.
module counter_4bit (
    input clk,
    input reset,
    output reg [3:0] count
);

    always @(posedge clk or posedge reset) begin
        if (reset)
            count <= 0;
        else
            count <= count + 1;
    end

endmodule
